import React, { useState, useEffect } from 'react';
import { API_KEY, API_MOVIE, API_TV } from '../constant';

const Keyword = (props) => {
  const { id, name } = props;
  const [data, setData] = useState([]);

  let api, obj;
  switch (name) {
    case 'movie':
      api = API_MOVIE;
      obj = 'keywords';
      break;

    case 'tv':
      api = API_TV;
      obj = 'results';
      break;
  
    default:
      break;
  }

  useEffect(() => {
    const getData = async () => {
      await fetch(api + id + '/keywords?api_key=' + API_KEY)
        .then((response) => {
          return response.json();
        })
        .then((data) => {
          setData(data[obj])
        })
        .catch((error) => {
          console.error(error);
        })
    }
    
    getData();
  }, [api, id, obj]);

  return (
    <div>
      <div className="text-bold mt-4">Keyword Cloud</div>
      <div>
        {data.length > 0 ? data.map((dataRow, index) => (
          <span className="badge bg-secondary" key={index}>{dataRow.name}</span>
        )) : '-'}
      </div>
    </div>
  )
}

export default Keyword
